mapper.select:
select distinct s.stock_id, p.product_id, p.product_name, p.expiration_date, s.stock_amount, i.inbound_date from product p join stock_table s on p.product_id = s.product_id join inbound_table i on i.product_id = p.product_id join business_table b on p.business_id = b.business_id WHERE b.user_id = #{userId}
AND p.product_name LIKE CONCAT('%', #{productName}, '%')
ORDER BY p.product_name LIMIT #{limit} OFFSET #{offset}
